function EditCursorGroup({cursor, setCursor} : {
    cursor: Cursor,
    setCursor: (c : Cursor) => void
}) {
    return <div className={"toolbarGroup"}>
        <span>{t`Cursor:`}</span>
        <button className={`btn ${cursor === Cursor.POINTER ? "btn-primary" : "btn-outline-primary"}`} title={t`Select / Group Move`} onClick={() => setCursor(Cursor.POINTER)}><i className="fa fa-mouse-pointer"></i></button>
        <button className={`btn ${cursor === Cursor.SINGLE ? "btn-primary" : "btn-outline-primary"}`} title={t`Single Place`} onClick={() => setCursor(Cursor.SINGLE)}><i className="fa fa-mouse-pointer fa-xs"><sup>+</sup></i></button>
        <button className={`btn ${cursor === Cursor.FILL ? "btn-primary" : "btn-outline-primary"}`} title={t`Fill Area`} onClick={() => setCursor(Cursor.FILL)}><i className="fa fa-crosshairs"></i></button>
        <button className={`btn ${cursor === Cursor.GRAB ? "btn-primary" : "btn-outline-primary"}`} title={t`Single Grab & Move`} onClick={() => setCursor(Cursor.GRAB)}><i className="fa fa-hand-paper"></i></button>
        <button className={`btn ${cursor === Cursor.TEXT ? "btn-primary" : "btn-outline-primary"}`} title={t`Label`} onClick={() => setCursor(Cursor.TEXT)}><i className="fa fa-i-cursor"></i></button>
        <button className={`btn ${cursor === Cursor.TEXT_ROT ? "btn-primary" : "btn-outline-primary"}`} title={t`Label (rot)`} onClick={() => setCursor(Cursor.TEXT_ROT)}><i className="fa fa-i-cursor fa-rotate-90"></i></button>
        <button className={`btn ${cursor === Cursor.DELETE ? "btn-danger" : "btn-outline-danger"}`} title={t`Delete`} onClick={() => setCursor(Cursor.DELETE)}><i className="fa fa-trash"></i></button>
    </div>
}

function AssignCursorGroup({cursor, setCursor, pitLabelMode} : {
    cursor: Cursor,
    setCursor: (c : Cursor) => void,
    pitLabelMode: LabelMode
}) {
    return <div className={"toolbarGroup"}>
        <span>{t`Cursor:`}</span>
        <button className={`btn ${cursor === Cursor.ASSIGN ? "btn-primary" : "btn-outline-primary"}`} title={t`Assign Value(s)`} onClick={() => setCursor(Cursor.ASSIGN)}><i className="fa fa-mouse-pointer"></i></button>
        {pitLabelMode === LabelMode.ADDRESS ? <button className={`btn ${cursor === Cursor.SINGLE ? "btn-primary" : "btn-outline-primary"}`} title={t`Quick Assign`} onClick={() => setCursor(Cursor.SINGLE)}><i className="fa fa-mouse-pointer fa-xs"><sup>+</sup></i></button> : null}
        {pitLabelMode !== LabelMode.NUMBER ? <button className={`btn ${cursor === Cursor.CLEAR ? "btn-primary" : "btn-outline-primary"}`} title={t`Delete`} onClick={() => setCursor(Cursor.CLEAR)}><i className="fa fa-trash fa-xs"></i></button> : null}
        <button className={`btn ${cursor === Cursor.INSPECT ? "btn-primary" : "btn-outline-primary"}`} title={t`Pit Info`} onClick={() => setCursor(Cursor.INSPECT)}><i className="fa fa-info-circle"></i></button>
    </div>
}

function CellGroup({cursor, cellType, setCellType}: {
    cursor: Cursor,
    cellType: CellType,
    setCellType: (c: CellType) => void
}) {
    const enabled = cursor === Cursor.SINGLE || cursor === Cursor.FILL;
    const noField = cursor === Cursor.FILL;
    return <div className={"toolbarGroup"}>
        <span>{t`Cell Type:`}</span>
        <button className={`btn ${cursor === Cursor.SINGLE && cellType === CellType.OPEN ? "btn-primary" : "btn-outline-primary"}`} disabled={!enabled} onClick={() => setCellType(CellType.OPEN)}>{t`Open`}</button>
        <button className={`btn ${cursor === Cursor.SINGLE && cellType === CellType.BOUNDARY ? "btn-primary" : "btn-outline-primary"}`} disabled={!enabled} onClick={() => setCellType(CellType.BOUNDARY)}>{t`Boundary`}</button>
        <button className={`btn ${cursor === Cursor.SINGLE && cellType === CellType.PIT ? "btn-primary" : "btn-outline-primary"}`} disabled={!enabled} onClick={() => setCellType(CellType.PIT)}>{t`Pit`}</button>
        <button className={`btn ${cursor === Cursor.SINGLE && cellType === CellType.FIELD ? "btn-primary" : "btn-outline-primary"}`} disabled={!enabled || noField} onClick={() => setCellType(CellType.FIELD)}>{t`Field`}</button>
        <button className={`btn ${cursor === Cursor.SINGLE && cellType === CellType.FIELD_ROT ? "btn-primary" : "btn-outline-primary"}`} disabled={!enabled || noField} onClick={() => setCellType(CellType.FIELD_ROT)}>{t`Field (rotated)`}</button>
        <button className={`btn ${cursor === Cursor.SINGLE && cellType === CellType.OBJECT ? "btn-primary" : "btn-outline-primary"}`} disabled={!enabled} onClick={() => setCellType(CellType.OBJECT)}>{t`Object`}</button>
        <button className={`btn ${cursor === Cursor.SINGLE && cellType === CellType.LABEL ? "btn-primary" : "btn-outline-primary"}`} disabled={!enabled} onClick={() => setCellType(CellType.LABEL)}>{t`Label`}</button>
    </div>
}

function UndoGroup({undo, redo} : {
    undo: () => void,
    redo: () => void
}){
    return <div className={"toolbarGroup"}>
        <span>{t`Undo:`}</span>
        <button className={`btn btn-outline-primary`} onClick={() => undo()}><i className="fa fa-undo"></i></button>
        <button className={`btn btn-outline-primary`} onClick={() => redo()}><i className="fa fa-repeat"></i></button>
    </div>
}

function ZoomGroup({zoom, zoomDispatch} : {
    zoom: number,
    zoomDispatch: (dir: 'in' | 'out') => void
}) {
    return <div className={"toolbarGroup"}>
        <span>{t`Zoom:`}{(zoom * 100).toFixed(0) + "%"}</span>
        <button className={`btn btn-outline-primary`} onClick={() => zoomDispatch('out')}><i className="fa fa-search-minus"></i></button>
        <button className={`btn btn-outline-primary`} onClick={() => zoomDispatch('in')}><i className="fa fa-search-plus"></i></button>
    </div>
}

function ColorGroup({color, used, setColor} : {
    color: string,
    used: string[],
    setColor: (color: string) => void
}) {
    const [showPicker, setShowPicker] = useState(false);
    return <div className={"toolbarGroup"}>
        <button className="btn btn-secondary btn-sm ml-3" onClick={() => setShowPicker(!showPicker)} style={{position: 'relative', top: '-.5rem'}}>{showPicker ? "Hide Picker" : "Pick Color"}</button>
        <div className="ml-2" onClick={() => setShowPicker(true)} style={{display: 'inline-block', width: '2em', height: '2em', background: color, position: 'relative', top: '.25rem'}}/>
        { showPicker ? <div style={{ position: 'absolute', zIndex: 2 }} className={"colorPicker"}>
            <div style={{ position: 'fixed', right: 0, top: '-.5rem' }} onClick={() => setShowPicker(false)}/>
            <BlockPicker colors={used} color={color} triangle="hide" onChangeComplete={(e) => setColor(e.hex)}/>
        </div> : null }
    </div>
}

